import os
import subprocess
from google.cloud import storage

def image_conversion(event, context):
    bucket_name = event['bucket']
    file_name = event['name']
    conversion_options = event.get('attributes', {}).get('conversion_options', '')

    # Define the input and output paths
    input_blob = f"gs://{bucket_name}/{file_name}"
    output_blob = f"gs://{bucket_name}/converted_{file_name}"

    # Download the image to the local filesystem
    local_input_path = f"/tmp/{file_name}"
    local_output_path = f"/tmp/converted_{file_name}"

    storage_client = storage.Client()
    bucket = storage_client.bucket(bucket_name)
    blob = bucket.blob(file_name)
    blob.download_to_filename(local_input_path)

    # Construct the ImageMagick convert command
    command = ['convert', local_input_path] + conversion_options.split() + [local_output_path]

    # Execute the command
    subprocess.call(command)

    # Upload the converted image back to Cloud Storage
    converted_blob = bucket.blob(f"converted_{file_name}")
    converted_blob.upload_from_filename(local_output_path)

    # Clean up local files
    os.remove(local_input_path)
    os.remove(local_output_path)